import React from 'react';
import { motion } from 'framer-motion';

const team = [
  { name: 'Имилиана Цонева', role: 'Адвокат', image: '/img/coneva.png' },
];

const Team = () => {
  const styles = {
    section: {
      padding: '120px 24px',
      backgroundColor: '#123524',
    },
    container: {
      maxWidth: '1280px',
      margin: '0 auto',
    },
    header: {
      textAlign: 'center',
      marginBottom: '64px',
    },
    tagline: {
      fontSize: '12px',
      textTransform: 'uppercase',
      letterSpacing: '4px',
      color: '#e2bc6f',
      marginBottom: '16px',
    },
    title: {
      fontFamily: 'Playfair Display, serif',
      fontSize: 'clamp(32px, 5vw, 48px)',
      fontWeight: 700,
    },
    grid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(4, 1fr)',
      gap: '24px',
    },
    card: {
      cursor: 'pointer',
    },
    imageWrapper: {
      position: 'relative',
      overflow: 'hidden',
      marginBottom: '20px',
    },
    image: {
      width: '100%',
      height: '320px',
      objectFit: 'cover',
      transition: 'filter 0.5s ease',
    },
    name: {
      fontFamily: 'Playfair Display, serif',
      fontSize: '20px',
      fontWeight: 600,
      marginBottom: '4px',
    },
    role: {
      color: '#e2bc6f',
      fontSize: '14px',
      marginBottom: '4px',
    },
    specialty: {
      color: '#bdbdc9',
      fontSize: '13px',
    },
  };

  return (
    <section id="team" style={styles.section}>
      <div style={styles.container}>
        <motion.div
          style={styles.header}
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
        >
          <p style={styles.tagline}>Our Team</p>
          <h2 style={styles.title}>Meet Our Attorneys</h2>
        </motion.div>

        <div style={styles.grid} className="team-grid">
          {team.map((member, index) => (
            <motion.div
              key={member.name}
              style={styles.card}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1 }}
              whileHover={{ y: -5 }}
            >
              <div style={styles.imageWrapper} className="team-image-wrapper">
                <img src={member.image} alt={member.name} style={styles.image} className="team-image" />
              </div>
              <h3 style={styles.name}>{member.name}</h3>
              <p style={styles.role}>{member.role}</p>
              <p style={styles.specialty}>{member.specialty}</p>
            </motion.div>
          ))}
        </div>
      </div>

      <style>{`
        .team-image-wrapper:hover .team-image { filter: grayscale(0%) !important; }
        @media (max-width: 968px) { .team-grid { grid-template-columns: repeat(2, 1fr) !important; } }
        @media (max-width: 640px) { .team-grid { grid-template-columns: 1fr !important; } }
      `}</style>
    </section>
  );
};

export default Team;
